omniProcessElements.propertySetConfig:
{
  "label": "Project / Action Name",
  "helpText": "A short descriptive name for this proposed federal action.",
  "required": true,
  "maxLength": 255
}

{
  "label": "Project Description",
  "helpText": "Briefly describe the proposed action, its location, and its purpose.",
  "required": true,
  "rows": 5
}

{
  "label": "Purpose and Need",
  "helpText": "Why is this action being proposed? What need does it address?",
  "required": false,
  "rows": 4
}

{
  "label": "Extraordinary Circumstances Present?",
  "helpText": "Check if any of the following apply: designated wilderness, critical habitat, wetlands, floodplains, cultural or historic properties, environmental justice communities, threatened/endangered species. See 40 CFR 1501.4(b) for the full list. When in doubt, check this box — a coordinator will review.",
  "required": false
}

{
  "label": "NAICS Code (optional)",
  "helpText": "Six-digit NAICS industry code for the applicant organization. Improves CE matching accuracy if known.",
  "required": false,
  "maxLength": 10
}

{
  "label": "Preliminary Recommendation",
  "value": "%ScreeningResult:Recommendation%",
  "helpText": "This is a preliminary assessment based on acreage and extraordinary circumstances only. The authoritative CE determination is made by a NEPA coordinator after submission using the full BRE screening rule set. Per OMB M-25-21: AI recommends, humans decide.",
  "readOnly": true
}

{
  "label": "Basis",
  "value": "%ScreeningResult:ClassificationBasis%",
  "readOnly": true
}

{
  "label": "Potentially Applicable Categorical Exclusions",
  "helpText": "These are active CE catalog entries for the selected agency. Your coordinator will verify applicability after submission.",
  "text": "%ScreeningResult:LibraryEntries%",
  "readOnly": true
}

{
  "label": "Proposed CE Citation (optional)",
  "helpText": "If you believe a specific CE applies, enter the CFR citation (e.g., 43 CFR 46.210(i)) or CE code (e.g., BLM B3.6). Leave blank if unsure — the coordinator will identify the applicable authority.",
  "required": false,
  "maxLength": 255
}

{
  "label": "Agency Project / Permit Number (optional)",
  "helpText": "Your agency-assigned project or permit tracking number, if one has been issued.",
  "required": false,
  "maxLength": 100
}

{
  "label": "Submission Summary",
  "fields": [
    {"label": "Lead Agency",              "value": "%AgencyAbbr%"},
    {"label": "Project Name",             "value": "%Name%"},
    {"label": "Action Type",              "value": "%nepa_action_type__c%"},
    {"label": "Sector",                   "value": "%nepa_project_sector__c%"},
    {"label": "Surface Disturbance (ac)", "value": "%nepa_disturbance_acres__c%"},
    {"label": "Extraordinary Circumstances", "value": "%ExtraordinaryCircumstances%"},
    {"label": "Preliminary Recommendation", "value": "%ScreeningResult:Recommendation%"}
  ]
}

{
  "label": "Your CE screening request has been submitted.",
  "value": "%SaveResult:ConfirmationMessage%",
  "readOnly": true,
  "helpText": "Reference number: %SaveResult:ProcessId%"
}
